def extract_text_from_pdfs(books_dir: Path) -> list[dict]:
    """Extract text chunks from all PDF files in the books directory."""
    chunks = []
    pdf_files = list(books_dir.glob("*.pdf"))

    if not pdf_files:
        print(f"  WARNING: No PDF files found in {books_dir}")
        return chunks

    for pdf_path in pdf_files:
        print(f"  Reading: {pdf_path.name}")
        try:
            reader = pypdf.PdfReader(str(pdf_path))
            full_text = ""
            for page_num, page in enumerate(reader.pages):
                text = page.extract_text()
                if text:
                    full_text += f"\n{text}"

            if not full_text.strip():
                print(f"    WARNING: No text extracted from {pdf_path.name} (may be a scanned image PDF)")
                continue

            # Split into overlapping chunks
            words = full_text.split()
            char_count = 0
            chunk_start = 0

            for i, chunk_text in enumerate(_sliding_window(full_text, CHUNK_SIZE, CHUNK_OVERLAP)):
                chunk_text = chunk_text.strip()
                if len(chunk_text) < 200:  # Skip very short chunks
                    continue
                # Filter out chunks that are mostly numbers/tables (not useful for Q&A)
                words_in_chunk = chunk_text.split()
                alpha_words = sum(1 for w in words_in_chunk if any(c.isalpha() for c in w))
                if alpha_words < len(words_in_chunk) * 0.4:
                    continue

                chunks.append({
                    "source": pdf_path.name,
                    "chunk_index": i,
                    "text": chunk_text,
                })

            print(f"    Extracted {len(chunks)} chunks so far from {pdf_path.name}")

        except Exception as e:
            print(f"    ERROR reading {pdf_path.name}: {e}")

    return chunks


def _sliding_window(text: str, size: int, overlap: int):
    """Generate overlapping text chunks."""
    start = 0
    while start < len(text):
        end = start + size
        yield text[start:end]
        start += size - overlap
        if start >= len(text):
            break


def is_spc_relevant(text: str) -> bool:
    """Return True if the text chunk appears to be SPC-relevant content."""
    keywords = [
        "control chart", "control limit", "UCL", "LCL", "Xbar", "X-bar",
        "range chart", "sigma", "standard deviation", "variation", "process",
        "capability", "Cpk", "Cp", "defect", "attribute", "variable", "sample",
        "subgroup", "Nelson", "out of control", "assignable cause", "common cause",
        "normal distribution", "specification", "tolerance", "DPMO",
        "six sigma", "histogram", "Pareto", "cause and effect", "fishbone",
    ]
    text_lower = text.lower()
    return sum(1 for kw in keywords if kw.lower() in text_lower) >= 2


def chunk_to_qa_pair(chunk: dict) -> dict | None:
    """Convert a PDF text chunk into a Q&A training pair."""
    text = chunk["text"]
    source = chunk["source"]

    if not is_spc_relevant(text):
        return None

    # Identify the topic from the chunk and create an appropriate prompt
    text_lower = text.lower()

    if "control limit" in text_lower or "ucl" in text_lower or "lcl" in text_lower:
        instruction = f"Explain the following concept about control chart limits from the SPC literature:\n\n{text[:600]}"
    elif "capability" in text_lower or "cpk" in text_lower or "cp " in text_lower:
        instruction = f"Explain the following concept about process capability from the SPC literature:\n\n{text[:600]}"
    elif "variation" in text_lower and ("common" in text_lower or "special" in text_lower or "assignable" in text_lower):
        instruction = f"Explain the following SPC concept about process variation:\n\n{text[:600]}"
    elif "six sigma" in text_lower or "dpmo" in text_lower:
        instruction = f"Explain the following Six Sigma concept from the SPC literature:\n\n{text[:600]}"
    elif "attribute" in text_lower and ("chart" in text_lower or "defect" in text_lower):
        instruction = f"Explain the following concept about attribute control charts:\n\n{text[:600]}"
    elif "histogram" in text_lower or "pareto" in text_lower or "cause" in text_lower:
        instruction = f"Explain the following process improvement concept from SPC practice:\n\n{text[:600]}"
    else:
        instruction = f"Explain the following Statistical Process Control concept:\n\n{text[:600]}"

    output = (
        f"This passage from the SPC literature ({source}) addresses an important concept in "
        f"Statistical Process Control:\n\n"
        f"{text}\n\n"
        f"Key takeaway: This passage should be understood in the context of using statistical "
        f"methods to distinguish between common cause variation (the normal, expected variation "
        f"inherent in any process) and special cause variation (identifiable, assignable sources "
        f"of variation that signal something has changed). The goal of SPC is always to first "
        f"achieve a state of statistical control, then improve the process's capability to meet "
        f"specifications."
    )

    return {"instruction": instruction, "output": output}


def main():
    OUTPUT_DIR.mkdir(parents=True, exist_ok=True)

    print("\n" + "="*60)
    print("SPC Training Dataset Extraction")
    print("="*60)

    all_pairs = []

    # Part 1: Add seed pairs (always included)
    print(f"\n[1/2] Loading {len(SEED_PAIRS)} seed Q&A pairs...")
    all_pairs.extend(SEED_PAIRS)
    print(f"      Done. {len(all_pairs)} pairs so far.")

    # Part 2: Extract from PDFs
    print(f"\n[2/2] Extracting Q&A pairs from PDFs in {BOOKS_DIR}...")
    chunks = extract_text_from_pdfs(BOOKS_DIR)
    print(f"      Extracted {len(chunks)} text chunks from PDFs.")

    auto_pairs = 0
    for chunk in chunks:
        pair = chunk_to_qa_pair(chunk)
        if pair:
            all_pairs.append(pair)
            auto_pairs += 1

    print(f"      Generated {auto_pairs} Q&A pairs from PDF content.")

    # Shuffle to mix seed and auto pairs
    import random
    random.seed(42)
    random.shuffle(all_pairs)

    # Write output
    with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
        for pair in all_pairs:
            f.write(json.dumps(pair, ensure_ascii=False) + "\n")

    print(f"\n{'='*60}")
    print(f"Dataset written to: {OUTPUT_FILE}")
    print(f"Total Q&A pairs:    {len(all_pairs)}")
    print(f"  - Seed pairs:     {len(SEED_PAIRS)}")
    print(f"  - Auto pairs:     {auto_pairs}")
    print(f"{'='*60}")

    if len(all_pairs) < 50:
        print("\nWARNING: Dataset is very small. The PDFs may be scanned images.")
        print("  The seed pairs (60) will still provide basic SPC fine-tuning.")
        print("  Consider adding markdown files to the books/ folder for more data.")


if __name__ == "__main__":
    main()
